const response = $.steps.scrapeWebsite.response || {};
const data = response.data || response;
const markdown = (data.markdown || data.content || data.text || '').slice(0, 8000);
const title = data.title || data.metadata?.title || '';
const url = $.input.companyUrl;
const name = $.input.companyName || title || url;

return { markdown, title, url, companyName: name, contentLength: markdown.length };

const data = $.steps.extractContent.output;

let prompt = 'You are a business analyst specializing in company research and enrichment. Analyze the following website content and extract structured company data.

';
prompt += 'COMPANY: ' + data.companyName + '
';
prompt += 'WEBSITE: ' + data.url + '

';
prompt += 'WEBSITE CONTENT:
' + data.markdown + '

';
prompt += 'INSTRUCTIONS:
';
prompt += 'Extract the following fields from the website content. If information is not available, use "Not found" as the value.

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "companyName": "official company name",
';
prompt += '  "market": "B2B or B2C or Both",
';
prompt += '  "industry": "primary industry",
';
prompt += '  "subIndustry": "specific niche",
';
prompt += '  "targetAudience": "who they serve",
';
prompt += '  "valueProposition": "main value prop in 1-2 sentences",
';
prompt += '  "products": ["product1", "product2"],
';
prompt += '  "companySize": "startup|small|medium|enterprise",
';
prompt += '  "techStack": ["tech1", "tech2"],
';
prompt += '  "keywords": ["keyword1", "keyword2", "keyword3"],
';
prompt += '  "summary": "3-4 sentence company description",
';
prompt += '  "founded": "year or Not found",
';
prompt += '  "headquarters": "location or Not found"
';
prompt += '}';
return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { companyName: $.input.companyName || 'Unknown', market: 'Not found', industry: 'Not found', subIndustry: 'Not found', targetAudience: 'Not found', valueProposition: raw.slice(0, 200), products: [], companySize: 'Not found', techStack: [], keywords: [], summary: raw.slice(0, 300), founded: 'Not found', headquarters: 'Not found' }; }

const ai = $.steps.parseAI.output;
const url = $.input.companyUrl;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Company Enrichment Complete', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*' + (ai.companyName || 'Unknown') + '* - <' + url + '|Website>' } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Market:*\n' + (ai.market || 'N/A') },
  { type: 'mrkdwn', text: '*Industry:*\n' + (ai.industry || 'N/A') }
] });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Target Audience:*\n' + (ai.targetAudience || 'N/A') },
  { type: 'mrkdwn', text: '*Company Size:*\n' + (ai.companySize || 'N/A') }
] });
blocks.push({ type: 'divider' });

const vp = (ai.valueProposition || 'N/A').slice(0, 500);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Value Proposition:*\n' + vp } });

if (ai.products && ai.products.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Products:* ' + ai.products.slice(0, 6).join(', ') } });
}

if (ai.summary) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Summary:*\n' + ai.summary.slice(0, 1000) } });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Data saved to Google Sheets | Powered by Firecrawl + Claude AI' }] });

const fallbackText = 'Company Enrichment: ' + (ai.companyName || url) + ' - ' + (ai.industry || 'Unknown industry') + ' (' + (ai.market || 'N/A') + ')';
return { blocks, fallbackText };
